def solution(limit: int = 1000) -> int:
    """
    Returns the perimeter p <= limit with the maximum number of integral right triangles.
    a^2 + b^2 = c^2 and a + b + c = p.
    """
    counts = [0] * (limit + 1)

    # p = a + b + sqrt(a^2 + b^2)
    # a^2 + b^2 = (p - a - b)^2
    # a^2 + b^2 = p^2 + a^2 + b^2 - 2pa - 2pb + 2ab
    # 0 = p^2 - 2pa - 2pb + 2ab
    # b = (p^2 - 2pa) / (2p - 2a)

    for p in range(2, limit + 1, 2):
        for a in range(1, p // 3):
            # Derived formula for b given p and a
            if (p * p - 2 * p * a) % (2 * p - 2 * a) == 0:
                counts[p] += 1

    max_val = max(counts)
    return counts.index(max_val)


